class Solution:
    def countDistinct(self, n):
        seen = set()
        for x in range(1, n + 1):
            y = str(x).replace('0', '')
            seen.add(y)
        return len(seen)

solutions.python:
class Solution:
    def countDistinct(self, n):
        s = str(n)
        L = len(s)
        total = 0
        for d in range(1, L):
            total += 9 ** d
        exact_possible = True
        for i in range(L):
            digit = int(s[i])
            if digit == 0:
                exact_possible = False
                break
            total += (digit - 1) * (9 ** (L - i - 1))
        if exact_possible:
            total += 1
        return total

