var countDistinct = function(n) {
    const s = String(n);
    const L = s.length;
    let total = 0;
    for (let d = 1; d < L; d++) total += Math.pow(9, d);
    let exactPossible = true;
    for (let i = 0; i < L; i++) {
        const digit = Number(s[i]);
        if (digit === 0) {
            exactPossible = false;
            break;
        }
        total += (digit - 1) * Math.pow(9, L - i - 1);
    }
    if (exactPossible) total += 1;
    return total;
};
